21	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
22	      const neighbor: Cell = [x + dx, y + dy];
23	      candidates.set(cellKey(neighbor), neighbor);
24	    }
25	  }
26	  const result: Cell[] = [];
