const survives = (neighbors: number): boolean => neighbors === 2 || neighbors === 3;

export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(cellKey));
  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    candidates.set(cellKey([x, y]), [x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      candidates.set(cellKey(neighbor), neighbor);
    }
  }
  const result: Cell[] = [];
  for (const cell of candidates.values()) {
    const n = countLiveNeighbors(cell, alive);
    const isAlive = alive.has(cellKey(cell));
    if ((isAlive && survives(n)) || (!isAlive && n === 3)) {
      result.push(cell);
    }
  }
  return result;
}

